import{_ as a,a as t,b as i}from"./chunks/支持留言.NiGCLVdp.js";import{_ as n,o,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Blog","description":"","frontmatter":{},"headers":[],"relativePath":"nl-NL/Other/blog.md","filePath":"nl-NL/Other/blog.md","lastUpdated":1781962217000}'),r={name:"nl-NL/Other/blog.md"};function d(p,e,c,g,h,b){return o(),s("div",null,[...e[0]||(e[0]=[l('<h1 id="blog" tabindex="-1">Blog <a class="header-anchor" href="#blog" aria-label="Permalink to &quot;Blog&quot;">​</a></h1><p>De blogfunctie voegt een zelfstandige blogpagina toe aan je ImgBed-site.</p><p>Na inschakelen kunnen bezoekers openen:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/blog/</span></span></code></pre></div><p><img src="'+a+'" alt="Bloghomepage" loading="lazy"></p><p>De blog is gebaseerd op het open-sourceproject <a href="https://github.com/LyraVoid/Mizuki" target="_blank" rel="noreferrer">LyraVoid/Mizuki</a>. ImgBed heeft deze opnieuw geïntegreerd met Vue, zodat hij als onderdeel van de image-hosting-site kan draaien.</p><h2 id="waar-je-dit-configureert" tabindex="-1">Waar je dit configureert <a class="header-anchor" href="#waar-je-dit-configureert" aria-label="Permalink to &quot;Waar je dit configureert&quot;">​</a></h2><p>Bloginstellingen staan onder:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Blog</span></span></code></pre></div><p><img src="'+t+'" alt="Bloginstellingen" loading="lazy"></p><h2 id="eerste-installatie" tabindex="-1">Eerste installatie <a class="header-anchor" href="#eerste-installatie" aria-label="Permalink to &quot;Eerste installatie&quot;">​</a></h2><ol><li>Schakel <code>Enable</code> in.</li><li>Selecteer het GitHub-account waarin de blogconfiguratie wordt opgeslagen.</li><li>Klik op <code>Update Blog</code>.</li><li>Wacht op de succesmelding.</li><li>Open <code>https://your-domain.com/blog/</code> om de blog te bekijken.</li></ol><p>Bij het eerste gebruik maakt ImgBed een privé GitHub-repository aan onder het gekozen account:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Deze repository bewaart bloginstellingen en artikelinhoud.</p><h2 id="berichten-schrijven" tabindex="-1">Berichten schrijven <a class="header-anchor" href="#berichten-schrijven" aria-label="Permalink to &quot;Berichten schrijven&quot;">​</a></h2><p>Blogberichten bewerk je in je privé GitHub-repository:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Typische werkwijze:</p><ol><li>Open GitHub.</li><li>Ga naar de privérepository <code>imgbed-blog-config</code>.</li><li>Bewerk of voeg berichtbestanden toe.</li><li>Commit de wijzigingen.</li><li>Ga terug naar het ImgBed-beheer en klik op <code>Update Blog</code>, of klik drie keer op het logo linksboven op de bloghomepage om een update te starten.</li></ol><p><code>Update Blog</code> overschrijft geen inhoud die je hebt geschreven. De actie is vooral bedoeld om de repository te initialiseren en de blogcache te verversen.</p><h2 id="ondersteunde-functies" tabindex="-1">Ondersteunde functies <a class="header-anchor" href="#ondersteunde-functies" aria-label="Permalink to &quot;Ondersteunde functies&quot;">​</a></h2><p>De blog ondersteunt gebruikelijke blogfuncties zoals berichtenlijsten, categorieën, tags, archieven, zoeken, dark mode en taalwisseling.</p><p>Ook reacties en bezoekstatistieken worden ondersteund.</p><p><img src="'+i+'" alt="Blogreacties" loading="lazy"></p><p>Reacties verschijnen onder berichten. Bezoekers kunnen avatar, nickname, e-mailadres en reactie invullen.</p><p>Bezoekstatistieken tonen artikelweergaven en sitebezoeken, zodat je blogverkeer beter kunt volgen.</p><h2 id="url" tabindex="-1">URL <a class="header-anchor" href="#url" aria-label="Permalink to &quot;URL&quot;">​</a></h2><p>De blog staat altijd onder <code>/blog/</code>.</p><p>Als je ImgBed-domein bijvoorbeeld is:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com</span></span></code></pre></div><p>dan is de blog-URL:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com/blog/</span></span></code></pre></div><p>Wanneer je de blog uitschakelt, kunnen bezoekers de blogpagina niet meer openen.</p>',34)])])}const v=n(r,[["render",d]]);export{k as __pageData,v as default};
